/**
 * GlassesJS — Main entry point
 *
 * Zero-model glasses detection for the browser.
 * Detects whether a person is wearing glasses using webcam video frames
 * and MediaPipe facial landmarks — no AI models, no server, no dependencies.
 *
 * @author Pavel Horak
 * @license MIT
 * @see https://glassesjs.com
 */
/**
 * GlassesJS — Standalone Detector
 *
 * Self-contained detector that handles MediaPipe FaceLandmarker
 * initialization internally. User just provides a video element.
 *
 * Two modes:
 * - detectOnce() — accumulate N frames, return Promise with result
 * - start(callback) — continuous detection, callback every X ms
 *
 * @author Pavel Horak
 * @license MIT
 */
